    }
}

arguments.new_str:
using Xunit;

namespace MyApp.Tests;

public class ConditionalTests
{
    [Fact]
    public void OnlyOnWindows()
    {
        if (!OperatingSystem.IsWindows())
            Assert.Skip("Requires Windows");
        Assert.True(true);
    }

    [Theory]
    [InlineData("feature-a")]
    [InlineData("feature-b")]
    public void OnlyWithFeature(string feature)
    {
        if (string.IsNullOrEmpty(Environment.GetEnvironmentVariable(feature)))
            Assert.Skip($"Environment variable '{feature}' is not set");
        Assert.NotNull(feature);
    }
}

